import importlib.util
import io
import json
import uuid
from pathlib import Path

import pytest

AC_UID = "8d0477aea3683987"
AC_TYPE = "hook"

_HOOK_PATH = (
    Path(__file__).resolve().parents[3] / "hooks" / "pretool-orchestrator-gate.py"
)


def _load_module():
    spec = importlib.util.spec_from_file_location(
        f"orchestrator_gate_{uuid.uuid4().hex}", _HOOK_PATH
    )
    mod = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod


def _drive_main(mod, monkeypatch, payload):
    """Drive main() with a stdin JSON payload; return the exit code.

    Treat a normal return or SystemExit(0/None) as not-blocked (code 0);
    SystemExit(2) as blocked. main() writes its state before exiting.
    """
    monkeypatch.setattr("sys.stdin", io.StringIO(json.dumps(payload)))
    try:
        mod.main()
        return 0
    except SystemExit as exc:
        code = exc.code
        if code is None:
            return 0
        return int(code)


def test_AC1(tmp_path, monkeypatch):
    """
    GIVEN: a fresh streak state in a throwaway temp state file
    WHEN:  the Bash-streak is accumulated across interleaved non-Bash tools, both at the component level (update_streak) and end-to-end (main())
    THEN:  interleaved non-Bash tools do NOT launder the Bash count; the 6th consecutive Bash reaches count==6 and is blocked (SystemExit code 2)
    """
    mod = _load_module()

    # --- Leg A: component (update_streak + enforce_streak_limit) ---
    leg_a_state = tmp_path / "leg_a.json"
    sequence = ["Bash", "Read", "Bash", "TodoWrite", "Bash", "Glob", "Bash", "Grep", "Bash"]
    for tool in sequence:
        mod.update_streak(leg_a_state, tool)

    parsed = mod.read_streak_state(leg_a_state)
    # The 5 Bash calls accumulated; the interleaved Read/TodoWrite/Glob/Grep
    # left bash_consecutive UNCHANGED (not reset to 1).
    assert parsed["bash_consecutive"] == {"last_tool": "Bash", "count": 5}

    # The 6th consecutive Bash reaches count==6.
    sixth = mod.update_streak(leg_a_state, "Bash")
    assert sixth == 6

    # The BLOCK is produced by enforce_streak_limit, NOT by update_streak.
    with pytest.raises(SystemExit) as exc_info:
        mod.enforce_streak_limit("Bash", 6)
    assert exc_info.value.code == 2

    # --- Leg B: end-to-end (main()) ---
    sid = f"ac1-{uuid.uuid4().hex}"
    state_file = tmp_path / "leg_b.json"
    monkeypatch.setattr(mod, "get_streak_state_file", lambda _sid: state_file)

    for tool in sequence:
        code = _drive_main(mod, monkeypatch, {"tool_name": tool, "session_id": sid})
        assert code == 0, f"main() unexpectedly blocked on {tool}"

    persisted = mod.read_streak_state(state_file)
    assert persisted["bash_consecutive"]["count"] == 5

    # The 6th consecutive Bash is blocked end-to-end through the real gate.
    final_code = _drive_main(mod, monkeypatch, {"tool_name": "Bash", "session_id": sid})
    assert final_code == 2
